// Reune todas las filas del query en un historial plano (orden cronologico ASC ya viene del SQL).
// Formato de salida:
//   usuario: ...
//   Agente: ...
const rows = $input.all();
const input = $('Execute Workflow Trigger').first().json;

function parseMsg(raw) {
  if (!raw) return null;
  let obj = raw;
  if (typeof raw === 'string') {
    try { obj = JSON.parse(raw); } catch { return null; }
  }
  const type = obj.type || obj.role;
  const content = (obj.data && obj.data.content) || obj.content || '';
  if (!type || !content) return null;
  const roleLabel = (type === 'human' || type === 'user') ? 'usuario' : 'Agente';
  return `${roleLabel}: ${String(content).replace(/\s+/g, ' ').slice(0, 500)}`;
}

const lines = rows
  .map(r => parseMsg(r.json.message))
  .filter(Boolean);

const history = lines.length > 0 ? lines.join('\n') : '(sin historial previo)';

return [{ json: {
  session_id: input.session_id,
  message: input.message,
  chat_history: history,
} }];

// Une chat_history (Format History) + estado actual del lead (Fetch Lead State)
// + el mensaje actual del trigger si aun no esta en el historial.
const format = $('Format History').first().json;
const trigger = $('Execute Workflow Trigger').first().json;
const current = $input.first().json;

// El GET devuelve un array con 0 o 1 fila.
const row = Array.isArray(current) ? (current[0] || {}) : (current || {});

function fmt(v) {
  if (v === null || v === undefined || v === '') return '(vacio)';
  return String(v);
}

const estado = [
  `- parcela_interes: ${fmt(row.parcela_interes)}`,
  `- forma_pago: ${fmt(row.forma_pago)}`,
  `- plazo: ${fmt(row.plazo)}`,
  `- uso: ${fmt(row.uso)}`,
].join('\n');

// Anexa el mensaje actual si NO aparece ya como ultimo turno user del historial.
const currentMsg = String(trigger.message || '').trim();
let historyText = (format.chat_history && format.chat_history !== '(sin historial previo)') ? format.chat_history : '';

if (currentMsg) {
  const userLines = historyText.split('\n').filter(l => l.startsWith('usuario:'));
  const lastUserContent = userLines.length > 0
    ? userLines[userLines.length - 1].replace(/^usuario:\s*/, '').trim()
    : '';
  if (lastUserContent !== currentMsg) {
    historyText = historyText
      ? `${historyText}\nusuario: ${currentMsg}`
      : `usuario: ${currentMsg}`;
  }
}

if (!historyText) historyText = '(sin historial)';

const prompt = `Datos ya guardados en la base para este lead (si un campo dice (vacio) significa que NO se ha guardado todavia):\n${estado}\n\nConversacion completa entre el usuario y el Agente principal (en orden cronologico):\n\n"""\n${historyText}\n"""`;

return [{ json: {
  prompt,
} }];

// Captura los datos del turno background para tracking de costos.
const trigger = $('Execute Workflow Trigger').first().json;

const endedAt = new Date().toISOString();
const startedAt = $execution?.startedAt || new Date(Date.now() - 3000).toISOString();
const durationMs = new Date(endedAt).getTime() - new Date(startedAt).getTime();

return [{
  json: {
    session_id: trigger.session_id,
    workflow: 'background_extractor',
    workflow_id: 'go161n2FpJp9to3c',
    execution_id: $execution.id,
    model: 'google/gemini-2.5-flash',
    user_message: (trigger.message || '').slice(0, 2000),
    agent_output: '',
    started_at: startedAt,
    ended_at: endedAt,
    duration_ms: durationMs,
  }
}];
